            >
              {agentState.isProcessing ? 'Agent Working...' : 'Trigger AI Agent'}
            </button>
          </div>

          {/* Unlocked Content Card */}
          <div className={`flex-1 p-6 rounded-xl border transition-all duration-700 ${
